import React, { useState, useEffect } from 'react';

interface PDFViewerProps {
  fileUrl: string;
}

const PDFViewer: React.FC<PDFViewerProps> = ({ fileUrl }) => {
  const [error, setError] = useState<string | null>(null);

  // Vérifier que l'URL est accessible
  useEffect(() => {
    if (!fileUrl) return;
    
    fetch(fileUrl, { method: 'HEAD' })
      .then(response => {
        if (!response.ok) {
          throw new Error(`HTTP ${response.status}`);
        }
      })
      .catch(err => {
        console.error('❌ PDF inaccessible:', err);
        setError(`🔐 Le PDF n'est pas accessible\n\nVérifiez que le bucket Supabase est PUBLIC :\n1. Storage → document-files\n2. Settings → Cochez "Public"\n3. Save`);
      });
  }, [fileUrl]);

  if (error) {
    return (
      <div className="h-full flex items-center justify-center bg-red-50 dark:bg-red-900/20 p-6 text-center">
        <div>
          <i className="fas fa-exclamation-triangle text-red-500 text-4xl mb-4"></i>
          <h3 className="text-lg font-bold text-red-800 dark:text-red-200 mb-2">Erreur de chargement</h3>
          <p className="text-red-700 dark:text-red-300 whitespace-pre-line mb-4">{error}</p>
          <button
            onClick={() => window.open(fileUrl, '_blank')}
            className="px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-md"
          >
            <i className="fas fa-file-pdf mr-2"></i>Ouvrir le PDF directement
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-gray-50 dark:bg-gray-800">
      {/* Barre d'outils simple */}
      <div className="flex items-center justify-between p-3 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-700/50">
        <span className="text-sm font-medium text-gray-700 dark:text-gray-300">
          <i className="fas fa-file-pdf text-red-500 mr-2"></i>
          Visualiseur PDF natif
        </span>
        <button
          onClick={() => window.open(fileUrl, '_blank')}
          className="px-3 py-1.5 text-sm bg-blue-600 hover:bg-blue-700 text-white rounded-md flex items-center gap-1.5"
        >
          <i className="fas fa-expand mr-1"></i>
          Plein écran
        </button>
      </div>
      
      {/* Affichage PDF NATIF (sans react-pdf) */}
      <div className="flex-1 overflow-auto p-4 bg-white dark:bg-gray-800">
        {fileUrl ? (
          <iframe
            src={fileUrl}
            title="PDF Viewer"
            className="w-full h-full min-h-[500px] border-0"
            sandbox="allow-same-origin allow-scripts allow-forms"
            onError={() => setError('❌ Impossible d\'afficher le PDF')}
          />
        ) : (
          <div className="h-full flex items-center justify-center text-gray-500 dark:text-gray-400">
            <p>Sélectionnez un document PDF pour commencer la transcription</p>
          </div>
        )}
      </div>
      
      <div className="py-2 px-4 text-center text-xs text-gray-600 dark:text-gray-400 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-700/50">
        ℹ️ Utilisez les contrôles natifs du navigateur pour zoomer/dézoomer
      </div>
    </div>
  );
};

export default PDFViewer;
